.darma-loader-uiverse-gooey-split-drops {
  position: relative;
  width: 1.5em;
  aspect-ratio: 1/2;
  filter: url(#gooey-split-drops-filter);
}

.darma-loader-uiverse-gooey-split-drops svg defs {
display: none
}

.darma-loader-uiverse-gooey-split-drops:before, .darma-loader-uiverse-gooey-split-drops:after {
content: '';
position: absolute;
inset: 0;
margin: auto;
width: 100%;
aspect-ratio: 1/1;
animation: 1.5s ease-out infinite darma-loader-uiverse-gooey-split-drops-loader;
border-radius: 50%;
}

.darma-loader-uiverse-gooey-split-drops:before {
background: linear-gradient(rgb(255, 206, 58), var(--loader-color, #42b549))
}

.darma-loader-uiverse-gooey-split-drops:after {
animation-delay: 0.75s;
background: linear-gradient(to top, var(--loader-secondary-color, #72dfe7), var(--loader-color, #42b549))
}

@keyframes darma-loader-uiverse-gooey-split-drops-loader {
0%, 50%, 100% {
transform: translateY(0)
}

25% {
transform: translateY(70%)
}

75% {
transform: translateY(-70%)
}
}

